import React, { useState } from 'react';
import { View, Text, TextInput, TouchableOpacity, StyleSheet, ScrollView } from 'react-native';

type Message = {
  id: number;
  from: 'user' | 'ai';
  text: string;
};

interface Props {
  context: string;
}

function getAssistantReply(context: string, userText: string): string {
  if (context.startsWith('report-step-1')) {
    return "You're starting a new incident. Choose the option that best matches what happened (collision, damage while parked, theft, or other). I'll guide you through the rest.";
  }
  if (context.startsWith('report-step-2')) {
    return 'Pick the vehicle involved and enter when the incident happened. A short, clear description helps the insurer understand the situation faster.';
  }
  if (context.startsWith('report-step-3')) {
    return 'Take one or two sharp photos of the damaged area. Make sure the plate and damage are visible, and avoid blurry shots.';
  }
  if (context.startsWith('report-step-4')) {
    return 'Confirm the spot on the map as close as possible to where the accident occurred. This helps with verification.';
  }
  if (context.startsWith('report-step-5')) {
    return 'Use voice input to describe what happened: where you were, speed, traffic, weather, and what the other vehicles did.';
  }
  if (context.startsWith('report-step-6')) {
    return 'Quickly review your photos, description and time of incident. When everything looks correct, you can safely submit the claim.';
  }
  return "I've noted that. In this prototype I only simulate guidance, but in a real version I would help you fill the form and check for missing info automatically.";
}

export default function AIAssistantPanel({ context }: Props) {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 1,
      from: 'ai',
      text: "Hi, I'm your MotorIQ assistant. Ask me anything about reporting this incident or understanding your claim.",
    },
  ]);
  const [input, setInput] = useState('');

  const handleSend = () => {
    if (!input.trim()) return;
    const userMessage: Message = {
      id: Date.now(),
      from: 'user',
      text: input.trim(),
    };
    const aiMessage: Message = {
      id: Date.now() + 1,
      from: 'ai',
      text: getAssistantReply(context, input.trim()),
    };
    setMessages((prev) => [...prev, userMessage, aiMessage]);
    setInput('');
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>MotorIQ assistant</Text>
      <ScrollView
        style={styles.messages}
        contentContainerStyle={{ paddingBottom: 8 }}
        showsVerticalScrollIndicator={false}
      >
        {messages.map((m) => (
          <View
            key={m.id}
            style={[
              styles.messageBubble,
              m.from === 'user' ? styles.userBubble : styles.aiBubble,
            ]}
          >
            <Text
              style={m.from === 'user' ? styles.userText : styles.aiText}
            >
              {m.text}
            </Text>
          </View>
        ))}
      </ScrollView>
      <View style={styles.inputRow}>
        <TextInput
          style={styles.input}
          value={input}
          onChangeText={setInput}
          placeholder="Ask for help with this step..."
        />
        <TouchableOpacity style={styles.sendButton} onPress={handleSend}>
          <Text style={styles.sendText}>Send</Text>
        </TouchableOpacity>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    borderRadius: 16,
    backgroundColor: '#0F172A',
    padding: 12,
    marginTop: 16,
  },
  title: {
    fontSize: 13,
    fontWeight: '600',
    color: '#E5E7EB',
    marginBottom: 8,
  },
  messages: {
    maxHeight: 120,
    marginBottom: 8,
  },
  messageBubble: {
    borderRadius: 12,
    paddingVertical: 6,
    paddingHorizontal: 10,
    marginBottom: 4,
    maxWidth: '90%',
  },
  aiBubble: {
    alignSelf: 'flex-start',
    backgroundColor: '#1F2937',
  },
  userBubble: {
    alignSelf: 'flex-end',
    backgroundColor: '#111827',
  },
  aiText: {
    fontSize: 12,
    color: '#E5E7EB',
  },
  userText: {
    fontSize: 12,
    color: '#F9FAFB',
  },
  inputRow: {
    flexDirection: 'row',
    alignItems: 'center',
    marginTop: 4,
  },
  input: {
    flex: 1,
    borderRadius: 999,
    backgroundColor: '#020617',
    color: '#E5E7EB',
    paddingHorizontal: 10,
    paddingVertical: 6,
    fontSize: 12,
    marginRight: 6,
  },
  sendButton: {
    paddingHorizontal: 10,
    paddingVertical: 6,
    borderRadius: 999,
    backgroundColor: '#2563EB',
  },
  sendText: {
    fontSize: 12,
    fontWeight: '600',
    color: '#F9FAFB',
  },
});
